WHERE paper_id = #{paperId}
  AND question_id = #{questionId}

mapper.select:
SELECT COUNT(1)
FROM exam_system.paper_question
WHERE paper_id = #{paperId}

SELECT COALESCE(SUM(question_score), 0)
FROM exam_system.paper_question
WHERE paper_id = #{paperId}

mapper.update:
